-- Migration 033: Taxonomy 4-category (L1/L2) model + 1,419 modern skills
--
-- Adds:
--   1. l1 (parent, 4 values), l2 (sub-type, 10 values), domain_tag, india_relevance columns
--   2. CHECK constraints (l1 enum, l2 enum, valid l1+l2 pair, domain_tag enum, india_relevance enum)
--   3. Helpful indexes (non-unique; the legacy table has at least one case-duplicate name)
--   4. 1,419 net-new contemporary skills (AI/ML, Modern SWE, Business/Ops, EdTech) tagged source='nexus_taxonomy_v2_2026_05'
--      For these new rows: category = l1 (per design decision); subcategory left NULL
--   5. A partial unique index on (lower(name)) WHERE source='nexus_taxonomy_v2_2026_05' so re-runs are idempotent
--
-- Existing 8,887 rows are NOT touched in this migration. Backfill of l1/l2 for legacy data is a separate task.
--
-- Run as a single transaction.

BEGIN;

-- ============================================================
-- 1. SCHEMA: add new columns
-- ============================================================
ALTER TABLE public.taxonomy_skills
  ADD COLUMN IF NOT EXISTS l1 text,
  ADD COLUMN IF NOT EXISTS l2 text,
  ADD COLUMN IF NOT EXISTS domain_tag text,
  ADD COLUMN IF NOT EXISTS india_relevance text;

COMMENT ON COLUMN public.taxonomy_skills.l1 IS
  'Parent category (Type-1). One of: TECHNICAL SKILLS, KNOWLEDGE, COMPETENCIES, CREDENTIAL.';
COMMENT ON COLUMN public.taxonomy_skills.l2 IS
  'Sub-type (Type-2). One of: Methodology, Technology, Tool, Domain, Knowledge, Ability, Competency, Skill, Certification, Language. Must form a valid pair with l1.';
COMMENT ON COLUMN public.taxonomy_skills.domain_tag IS
  'Functional domain: AI/ML/Data, Modern SWE, Business/Ops, EdTech/L&D, Cross-cutting.';
COMMENT ON COLUMN public.taxonomy_skills.india_relevance IS
  'India relevance flag: india_specific, india_strong, global.';

-- ============================================================
-- 2. CONSTRAINTS
-- ============================================================
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'taxonomy_skills_l1_check') THEN
    ALTER TABLE public.taxonomy_skills
      ADD CONSTRAINT taxonomy_skills_l1_check
      CHECK (l1 IS NULL OR l1 IN ('TECHNICAL SKILLS','KNOWLEDGE','COMPETENCIES','CREDENTIAL'));
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'taxonomy_skills_l2_check') THEN
    ALTER TABLE public.taxonomy_skills
      ADD CONSTRAINT taxonomy_skills_l2_check
      CHECK (l2 IS NULL OR l2 IN (
        'Methodology','Technology','Tool',
        'Domain','Knowledge',
        'Ability','Competency','Skill',
        'Certification','Language'
      ));
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'taxonomy_skills_l1_l2_pair_check') THEN
    ALTER TABLE public.taxonomy_skills
      ADD CONSTRAINT taxonomy_skills_l1_l2_pair_check
      CHECK (
        (l1 IS NULL AND l2 IS NULL) OR
        (l1 = 'TECHNICAL SKILLS' AND l2 IN ('Methodology','Technology','Tool')) OR
        (l1 = 'KNOWLEDGE'        AND l2 IN ('Domain','Knowledge')) OR
        (l1 = 'COMPETENCIES'     AND l2 IN ('Ability','Competency','Skill')) OR
        (l1 = 'CREDENTIAL'       AND l2 IN ('Certification','Language'))
      );
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'taxonomy_skills_domain_tag_check') THEN
    ALTER TABLE public.taxonomy_skills
      ADD CONSTRAINT taxonomy_skills_domain_tag_check
      CHECK (domain_tag IS NULL OR domain_tag IN ('AI/ML/Data','Modern SWE','Business/Ops','EdTech/L&D','Cross-cutting'));
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'taxonomy_skills_india_relevance_check') THEN
    ALTER TABLE public.taxonomy_skills
      ADD CONSTRAINT taxonomy_skills_india_relevance_check
      CHECK (india_relevance IS NULL OR india_relevance IN ('india_specific','india_strong','global'));
  END IF;
END $$;

-- ============================================================
-- 3. INDEXES (non-unique on name; legacy has case-duplicates)
-- ============================================================
CREATE INDEX IF NOT EXISTS idx_taxonomy_skills_l1 ON public.taxonomy_skills (l1);
CREATE INDEX IF NOT EXISTS idx_taxonomy_skills_l2 ON public.taxonomy_skills (l2);
CREATE INDEX IF NOT EXISTS idx_taxonomy_skills_l1_l2 ON public.taxonomy_skills (l1, l2);
CREATE INDEX IF NOT EXISTS idx_taxonomy_skills_domain_tag ON public.taxonomy_skills (domain_tag);
CREATE INDEX IF NOT EXISTS idx_taxonomy_skills_india_relevance ON public.taxonomy_skills (india_relevance);

-- Partial unique index over the v2 import only (so this migration is idempotent on re-run)
CREATE UNIQUE INDEX IF NOT EXISTS uniq_taxonomy_skills_v2_2026_05_name_lower
  ON public.taxonomy_skills (lower(name))
  WHERE source = 'nexus_taxonomy_v2_2026_05';

-- ============================================================
-- 4. BULK INSERT: 1,419 net-new modern skills
--    Skip on re-run via the partial unique index.
-- ============================================================
ON CONFLICT ((lower(name))) WHERE source = 'nexus_taxonomy_v2_2026_05' DO NOTHING;

COMMIT;

